import { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../utils/api';
import { PAPER_BOTS } from '../utils/constants';

export default function useRisk() {
  const [risk, setRisk] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const hasLoaded = useRef(false);

  const fetchAll = useCallback(async () => {
    if (!hasLoaded.current) setLoading(true);
    setError(null);
    try {
      const [
        exposureData,
        correlationData,
        drawdownData,
        dynamicData,
        featuresData,
        importanceData,
        riskBudgets,
        healthData,
        positionsData,
        attributionData,
      ] = await Promise.all([
        api('/risk/exposure').catch(() => null),
        api('/risk/correlation').catch(() => null),
        api('/risk/drawdown').catch(() => null),
        api('/risk/dynamic').catch(() => null),
        api('/risk/dynamic/features').catch(() => null),
        api('/risk/dynamic/importance').catch(() => null),
        api('/accounts/risk-budgets').catch(() => null),
        api('/control/health').catch(() => null),
        api('/positions').catch(() => null),
        api('/v2/console/risk-attribution').catch(() => null),
      ]);

      // API returns { exposure: [...], total_equity } — normalize; exclude paper/marketing bots
      // PAPER_BOTS imported from constants — Layla/paper/demo never included in equity or exposure
      const allBots = exposureData?.exposure || exposureData?.bots || [];
      const bots = allBots.filter(b => {
        const name = (b?.bot_name || b?.bot || '').toLowerCase();
        const mode = (b?.mode || '').toLowerCase();
        return mode !== 'paper' && !PAPER_BOTS.has(name);
      });
      const totalEquity = bots.reduce((s, b) => s + (b.equity || 0), 0)
        || exposureData?.total_equity || 0;
      const totalExposure = bots.reduce((s, b) => s + (b.positions_value || b.exposure || 0), 0);

      // Build exposure table from per-bot data
      const exposure = bots.map(b => ({
        sector: b.bot_name || b.bot || 'Unknown',
        region: 'US',
        exposure: b.positions_value || b.equity || 0,
        pct: b.exposure_pct || (totalEquity > 0 ? ((b.positions_value || b.exposure || 0) / totalEquity * 100) : 0),
        buying_power: b.buying_power || 0,
        positions: b.positions_count || 0,
      }));

      // Normalize correlation — API returns { correlation: {sym: {sym: val}}, symbols: [...] }
      // Convert to { symbols: [...], matrix: [[...]] } for heatmap rendering
      let correlation = correlationData;
      if (correlationData?.correlation) {
        const corrObj = correlationData.correlation;
        // Use symbols from API if available, otherwise extract from correlation keys
        const symbols = correlationData.symbols || Object.keys(corrObj);
        const matrix = symbols.map(s1 => symbols.map(s2 => corrObj[s1]?.[s2] ?? 0));
        correlation = { ...correlationData, symbols, matrix };
      }

      // Normalize drawdown
      const ddBots = drawdownData?.bots || [];
      const maxDD = drawdownData?.backtest?.max_drawdown
        ?? (ddBots.length > 0 ? Math.max(0, ...ddBots.map(b => b.drawdown_pct || 0)) : 0);

      // Build drawdown bot stats for display (even when no historical series)
      const drawdownBots = ddBots.length > 0 ? ddBots : bots;
      const drawdownSeries = drawdownData?.series || null;

      // Normalize positions for risk contribution
      const allPositions = positionsData?.positions
        || positionsData?.bots?.flatMap(b => (b.positions || []).map(p => ({ ...p, bot: b.bot || b.bot_name })))
        || [];

      // Normalize risk budgets
      const budgets = riskBudgets?.budgets || riskBudgets?.accounts || riskBudgets || [];

      // Normalize kill switch from health data
      const killSwitch = {
        active: healthData?.kill_switch === true || healthData?.kill_switch_active === true,
        status: healthData?.status || 'unknown',
        uptime: healthData?.uptime || null,
        bots_online: healthData?.bots_online ?? healthData?.bots?.filter(b => b.healthy || b.status === 'online')?.length ?? null,
        bots_total: healthData?.bots_total ?? healthData?.bots?.length ?? null,
        last_check: healthData?.last_check || healthData?.timestamp || null,
        gating: healthData?.gating || null,
      };

      // Normalize dynamic risk model
      const dynamicRisk = dynamicData || null;

      // Normalize features
      const riskFeatures = featuresData?.features || featuresData || [];

      // Normalize feature importance
      const featureImportance = importanceData?.importance || importanceData?.features || importanceData || [];

      // Normalize risk attribution (per-position risk contribution)
      const riskAttribution = attributionData?.attribution || attributionData?.positions || attributionData || [];

      setRisk({
        totalExposure: totalExposure,
        portfolioHeat: totalEquity > 0 ? (totalExposure / totalEquity * 100) : 0,
        maxDrawdown: maxDD,
        correlationRisk: correlationData?.risk_level || 'Low',
        exposure,
        drawdown: drawdownSeries,
        drawdownBots: drawdownBots,
        bots: drawdownBots,
        correlation,
        positions: allPositions,
        riskBudgets: budgets,
        killSwitch,
        dynamicRisk,
        riskFeatures,
        featureImportance,
        riskAttribution,
        totalEquity,
        healthData,
      });
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
    hasLoaded.current = true;
  }, []);

  useEffect(() => {
    fetchAll();
    const interval = setInterval(fetchAll, 60000);  // 60s — risk changes slowly
    return () => clearInterval(interval);
  }, [fetchAll]);

  return { risk, loading, error };
}
